window.__QUIZ_DATA__=[{"id":"theory>Biology Practical>2013>1>a>i","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Study specimens A, B C and D carefully and use them to answer questions 1(a) to 1(d).    Name the phylum to which each of specimens A and D belong.","images":[],"marking_scheme":"Phylum of specimens A and D    A- cassava/Sugar/Sweet Potato. Tracheophvta/Angiospermatophyta/Angiospemophyta/Spermatophyta     D-Spirogyra-Thallophyta/Chlorophyta.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>1>a>ii","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Study specimens A, B C and D carefully and use them to answer questions 1(a) to 1(d).  Name the habitat or each Specimens A and D.","images":[],"marking_scheme":"Habitat of specimen A and D:  Habitat of A=Farmland/Grassland/Garden.     Habitat of D=Stream/ponds/puddles/ditches.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>1>b>i","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Name the type of reproduction common to specimens A, B, C and D.","images":[],"marking_scheme":"Type  common to all specimens: Asexual/vegetative Reproduction","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>1>b>ii","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"List the method of reproduction of each of specimens A, B,C and D giving one reason each for the method of reproduction listed.","images":[],"marking_scheme":"Method of ReproductionReasonSpecimen A(Cassava)-Cutting/stem cuttingPresence of budsSpecimen B(Plantain)-SuckerPresence of axillary buds/budsSpecimen C(Runner of grass)-runnersPresence of terminal buds on stem/rhizomeSpecimen D(Spirogyra)-FragmentationCells joined end to end on the filaments","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>1>c","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"c","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : COMMUNITY","question":"In a tabular form, state three observable differences between specimens B and C.","images":[],"marking_scheme":"Specimen B (Banana Sucker)Specimen C (Runner of Grass)Erect/vertical stemHorizontal/creeping stemThick/Swollen stemSlender/thin/narrow stemInternode not conspicuousInternode is conspicuous","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>1>d","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"d","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Make a drawing 8-10 cm long of specimens A to show the essential parts and label fully.","images":["data:image/jpeg;base64,","data:image/jpeg;base64,","data:image/jpeg;base64,"],"marking_scheme":"Drawing/Diagram of specimen A/Cassava stem    Drawing/Diagram of specimen A/Sugarcane stem    Drawing/Diagram of specimen A/stem of sweet potato","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>2>a>i","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : LIFE CYCLES","question":"Study specimens E, F, G1 and G2 carefully and use them to answer questions 2(a) to 2(d).    Name the life process in mammals that is associated with specimens E","images":[],"marking_scheme":"Life process in mammals associated with specimen F:    -External Respiration/Respiration/ Gaseous exchange/Breathing.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>2>a>ii","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : PLANT STRUCTURE","question":"State two structural similarities between the surface of specimen E and the skin of specimen F.","images":[],"marking_scheme":"-both richly supplied with blood capillaries/vascularised,  -both have thin surface;  -both are moist,  -both have large surface area.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>2>b>i","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Name the habitat in which specimen F will function efficiently.","images":[],"marking_scheme":"Land/ terrestrial/Moist place/ Pond","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>2>b>ii","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Explain how two observable features of specimens F adapt the organism to its habitats.","images":[],"marking_scheme":"-Streamlined body for ease movement in water,  - Webbed digits of hind limb(s) for swimming  -Presence of poisonous gland for protection against predators  -Muscular long hind limbs for hopping/jumping:  -Stout short forelimbs for absorbing shock on landing.  -large bulging eyes for wide vision.   -Moist skin for gaseous for exchange/breathing/respiration","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2013>2>c>i","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : PLANT STRUCTURE","question":"Using the blade provided cut a thin transverse section of the stem of specimens G add two drops of freshly prepared iodine solution to the cut section.              Record your observation and inferences :","images":[],"marking_scheme":"cortex stained blue-black, starch present in the cortex.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>2>c>ii","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : PLANT STRUCTURE","question":"In which part of the stem is food stored.","images":[],"marking_scheme":"Part of stem where food is stored: cortex/parenchyma","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>2>c>iii","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"iii","group":"","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"Name two tissues used for transportation of materials in specimens G,","images":[],"marking_scheme":"Tissues for transportation in G:  Xylem; phloem","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>2>c>iv","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"iv","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"List two supporting tissues present in specimen G,","images":[],"marking_scheme":"Supporting Tissues in G; Collenechyma, scelerenechyma, xylem, parenchyma.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>2>d","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"d","group":"","topic":"CONCEPT OF LIVING : PLANT STRUCTURE","question":"Make a drawing 10-12 cm long of a cut transverse section of the stem of specimen G, and label fully.","images":["data:image/jpeg;base64,"],"marking_scheme":"Drawing of Transverse section of the stem of specimen G/Waterleaf plant","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>3>a","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"a","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Study specimens L, M, N, P, Q, R and S carefully and use them to answer questions 4(a) to 4(d).    Name two specimens which can be used for the following: (i) reproduction; (ii) protection; (iii) movement.","images":[],"marking_scheme":"The specimens are  L is skin of goat/cow, M is Quill feather, N is shell of snail, P is Irish potato, Q is Twig of hibiscus, R is cutting of cassava, S is hind wing of cockroach.  Specimen used for reproduction:   - Irish potato/Specimen P   - Twig of Hibiscus/Dougainvillea/specimen   Q  -Cutting of cassava/Specimen R.    (ii) Specimens used for protection: - Skin Of a goat/sheep/cow/Specimen L.   - Quill feather/ specimen M  - Shell of a snail/ specimen N    (iii) Specimens used for movement   - Specimens M/Feather (Quill) Specimens S/ Hind wing of a cockroach.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>3>b","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"b","group":"","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"Stating observable features in specimens L, M, N, P,Q and R, Suggest one reason each for the answers given in 4(a)i), (ii) and (iii) above.","images":[],"marking_scheme":"For reproduction: P/lrish potato-presence of buds/eye(s), for sprouting to produce/new shoot.    Q/ Twig of Hibiscus/Bougainvillea-has buds, for sprouting.    R/cutting of cassava- has buds, for sprouting.    For protection: L/Skin of a goat - presence of hairs/sheet-like structure to protect the body against mechanical injury.    M/Feather-broad and smooth to cover body and prevent wetting/provides insulation.    N/ Shell-hard/calcareous nature to protect soft body of snail.    For movement: M/Feather-those of wings and tail are flat and air-tight for flight.    S/Hind wing of cockroach-light and flexible for flight.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>3>c>i","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"i","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"State two observable similarities between specimens P and R.","images":[],"marking_scheme":"- Both Specimens have buds for reproduction.   - both are stems.   - both have lenticel.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>3>c>ii","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"State two differences between specimens P and R.","images":[],"marking_scheme":"Specimen P Specimen RThe buds are buried in the tuberThe buds protrude from the stemThe buds are covered with scale leavesThe buds are not coveredIt stores foodIt does not store food","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2013>3>d>i","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"i","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Sate how observable features of specimen M adapt the specimen to its functions.","images":[],"marking_scheme":"- Vane is stiff; to enable it withstand air pressure during flight.  - Vane is broad, to provide a large Surface area for air lift.  - Vane is made up of barbs interlocked by barbulous, providing air light surface for flight.  - The quill is light and hollow, for buoyancy,   -The surface is water proof, to prevent birds from getting wet.","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2013>3>d>ii","subject":"Biology Practical","year":"2013","type":"Practical","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"Arrange specimens L, M, N and S in the increasing order of  complexity of the organism to which they belong.","images":[],"marking_scheme":"Increasing order of complexity: S \u2192 N \u2192 M\u2192L. OR Cockroach\u2192 Snail \u2192 Bird\u2192 Goat/Sheep/Cow.","marks":"1","difficulty":"2"}];